def validate_segment_specificity(segments: list) -> dict:
    """Validate segment definitions are specific."""
    issues = []

    for i, segment in enumerate(segments):
        required = ["role", "industry", "pain", "outcome", "cta_deliverable"]
        missing = [f for f in required if not segment.get(f)]

        if missing:
            issues.append(f"Segment {i+1}: Missing {missing}")

        # Check for generic language
        generic_terms = ["grow", "scale", "improve", "help"]
        outcome = segment.get("outcome", "").lower()
        if any(term in outcome and len(outcome.split()) < 5 for term in generic_terms):
            issues.append(f"Segment {i+1}: Outcome too generic")

    return {
        "passed": len(issues) == 0,
        "segment_count": len(segments),
        "issues": issues
    }


def validate_followup_value(followups: list) -> dict:
    """Validate each follow-up adds new value."""
    issues = []
    value_indicators = ["framework", "example", "case", "insight", "idea", "here's", "thought"]

    for i, followup in enumerate(followups):
        body = followup.get("body", "").lower()

        # Check for bumping language
        bump_phrases = ["bumping", "following up", "checking in", "circling back"]
        if any(phrase in body for phrase in bump_phrases):
            has_value = any(ind in body for ind in value_indicators)
            if not has_value:
                issues.append(f"Follow-up {i+1}: Bump without new value")

    return {
        "passed": len(issues) == 0,
        "followup_count": len(followups),
        "issues": issues
    }
